function greet(name) {
  return `Hello, ${name}!`;
}
function farewell(name) {
  return `Goodbye, ${name}!`;
}
module.exports = { greet, farewell };

// app.js — open the box
const { greet, farewell } = require('./greet');

console.log(greet('Alice'));
console.log(farewell('Alice'));

