// mathUtils.js
function double(n) {
  return n * 2;
}

function isEven(n) {
  return n % 2 === 0;
}

module.exports = { double, isEven };

// index.js
const { double, isEven } = require('./mathUtils');

console.log('double(7):', double(7));   // 14
console.log('isEven(4):', isEven(4));   // true
console.log('isEven(7):', isEven(7));   // false

